        }
      ]
    },
    {
      "order": 2,
      "title": "꽈리고추 손질하기",
      "description": [
        {
          "content": "꽈리고추 10개 정도를 준비해 주세요.",
          "start": "00:00:32",
          "end": "00:00:39"
        },
        {
          "content": "꽈리고추 끝부분을 조금만 잘라주세요.",
          "start": "00:00:39",
          "end": "00:00:51"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:00:39",
          "end": "00:00:51",
          "label": "끝부분 자르기"
        }
      ]
    },
    {
      "order": 3,
      "title": "양념장 만들기",
      "description": [
        {
          "content": "양념장 그릇에 양조간장 4스푼(40g)을 넣어주세요.",
          "start": "00:00:51",
          "end": "00:00:55"
        },
        {
          "content": "흑설탕 1스푼(13g)을 넣어주세요.",
          "start": "00:00:55",
          "end": "00:01:00"
        },
        {
          "content": "물엿 2스푼(26g)을 넣어주세요.",
          "start": "00:01:00",
          "end": "00:01:03"
        },
        {
          "content": "다진 마늘 1스푼(20g)을 넣어주세요.",
          "start": "00:01:03",
          "end": "00:01:07"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 4,
      "title": "양념장 완성하기",
      "description": [
        {
          "content": "짜장가루를 준비해 주세요.",
          "start": "00:01:07",
          "end": "00:01:12"
        },
        {
          "content": "짜장가루 1스푼을 넣어주세요.",
          "start": "00:01:12",
          "end": "00:01:18"
        },
        {
          "content": "맛술 4스푼(40g)을 넣어주세요.",
          "start": "00:01:18",
          "end": "00:01:26"
        },
        {
          "content": "양념 재료가 잘 섞이도록 저어주세요.",
          "start": "00:01:26",
          "end": "00:01:32"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 5,
      "title": "닭다리 초벌 굽기 준비",
      "description": [
        {
          "content": "팬 또는 웍에 참기름 1스푼을 둘러주세요.",
          "start": "00:01:32",
          "end": "00:01:39"
        },
        {
          "content": "팬에 닭다리를 올려주세요.",
          "start": "00:01:39",
          "end": "00:01:48"
        },
        {
          "content": "불을 켜고 불세기를 중약 불로 조절해 주세요.",
          "start": "00:01:48",
          "end": "00:01:52"
        },
        {
          "content": "뚜껑을 덮어주세요.",
          "start": "00:01:52",
          "end": "00:01:57"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:01:48",
          "end": "00:01:52",
          "label": "중약 불"
        }
      ]
    },
    {
      "order": 6,
      "title": "닭다리 뒤집어가며 굽기",
      "description": [
        {
          "content": "8~10분간 구워 노릇해지면 닭다리를 뒤집어주세요.",
          "start": "00:01:57",
          "end": "00:02:00"
        },
        {
          "content": "다시 뚜껑을 덮고 8~10분 정도 구워주세요.",
          "start": "00:02:00",
          "end": "00:02:04"
        },
        {
          "content": "닭다리를 전체적으로 노릇하게 구워주세요.",
          "start": "00:02:04",
          "end": "00:02:12"
        }
      ],
      "timerSeconds": 480,
      "scenes": [
        {
          "start": "00:01:57",
          "end": "00:02:00",
          "label": "노릇해지면 뒤집기"
        }
      ]
    },
    {
      "order": 7,
      "title": "식혜 넣고 1차로 조리기",
      "description": [
        {
          "content": "식혜 1캔을 준비해 주세요.",
          "start": "00:02:12",
          "end": "00:02:15"
        },
        {
          "content": "식혜 약 200ml 정도를 팬에 부어주세요.",
          "start": "00:02:15",
          "end": "00:02:23"
        },
        {
          "content": "불세기를 강 불로 조절하고 닭다리를 뒤집어가며 조려주세요.",
          "start": "00:02:23",
          "end": "00:02:37"
        },
        {
          "content": "식혜가 자박해질 때까지 조려주세요.",
          "start": "00:02:37",
          "end": "00:02:43"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:02:37",
          "end": "00:02:43",
          "label": "자박해질 때까지"
        }
      ]
    },
    {
      "order": 8,
      "title": "양념장과 꽈리고추 넣고 2차로 조리기",
      "description": [
        {
          "content": "준비한 양념장을 부어주세요.",
          "start": "00:02:43",
          "end": "00:02:46"
        },
        {
          "content": "준비한 꽈리고추를 넣어주세요.",
          "start": "00:02:46",
          "end": "00:02:50"
        },
        {
          "content": "강 불에서 양념장을 끼얹어가며 닭다리를 뒤집어 조려주세요.",
          "start": "00:02:50",
          "end": "00:03:00"
        },
        {
          "content": "양념이 자박해질 때까지 계속 조려주세요.",
          "start": "00:03:00",
          "end": "00:03:13"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:02:50",
          "end": "00:03:00",
          "label": "양념장 끼얹기"
        },
        {
          "start": "00:03:00",
          "end": "00:03:13",
          "label": "양념이 자박하게"
        }
      ]
    },
    {
      "order": 9,
      "title": "통깨 뿌려 마무리하기",
      "description": [
        {
          "content": "불을 끄고 통깨를 뿌려 마무리해 주세요.",
          "start": "00:03:13",
          "end": "00:03:22"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    }
  ],
  "servingTip": "남은 양념에 밥을 볶아 드세요."
}
